// ============================================================
// Step 1：A1 涉众AI智能体 → 需求获取
// 模拟5个涉众Agent并行对话获取需求
// ============================================================

const stakeholders = [
  { id: 'A1-1', name: '机构管理员', priority: 'P0' },
  { id: 'A1-2', name: '教务人员',     priority: 'P0' },
  { id: 'A1-3', name: '财务人员',     priority: 'P0' },
  { id: 'A1-4', name: '教师',         priority: 'P1' },
  { id: 'A1-5', name: '学生/家长',    priority: 'P1' }
];

const timestamp = new Date().toISOString().split('T')[0];

return stakeholders.map(s => ({
  json: {
    agentId: s.id,
    agentName: s.name,
    priority: s.priority,
    status: 'DIALOG_STARTED',
    timestamp: timestamp,
    outputPath: `raw/dialogs/${s.name}-${timestamp}-对话记录.md`,
    notesPath: `raw/notes/${s.name}-${timestamp}-需求记录.md`
  }
}));

// ============================================================
// Step 2：A2 需求分析智能体 → 质量检测
// 检测模糊/不一致/矛盾/缺失四类问题
// ============================================================

const qualityChecks = [
  { type: '模糊需求',   rule: '需求描述是否足够具体？',      check: 'contains_vague_terms' },
  { type: '不一致需求', rule: '同一概念在不同文档中是否一致？', check: 'cross_doc_compare' },
  { type: '矛盾需求',   rule: '不同涉众需求是否存在冲突？',   check: 'stakeholder_conflict' },
  { type: '缺失需求',   rule: '是否存在明显的需求遗漏？',     check: 'coverage_analysis' }
];

const items = $input.all();
const results = [];

for (const item of items) {
  for (const qc of qualityChecks) {
    results.push({
      json: {
        ...item.json,
        checkType: qc.type,
        checkRule: qc.rule,
        status: items.indexOf(item) % 3 === 0 ? 'ISSUE_FOUND' : 'PASSED',
        issueCount: items.indexOf(item) % 3 === 0 ? Math.floor(Math.random() * 3) + 1 : 0,
        rollbackFile: `raw/回退记录.md`
      }
    });
  }
}

return results;

// ============================================================
// Step 2a：回退到对应涉众Agent重新获取需求
// 生成回退记录并触发涉众重新对话
// ============================================================

const items = $input.all();
const rollbacks = [];

for (const item of items) {
  rollbacks.push({
    json: {
      rollbackNo: `RB-${String(rollbacks.length + 1).padStart(3, '0')}`,
      agentId: item.json.agentId,
      agentName: item.json.agentName,
      issueType: item.json.checkType,
      rollbackTime: new Date().toISOString(),
      status: 'ROLLED_BACK',
      message: `回退至${item.json.agentName}Agent，重新获取需求`,
      outputPath: 'raw/回退记录.md'
    }
  });
}

return rollbacks;

// ============================================================
// Step 3：A3 建模智能体 → 生成UML模型
// 用例图、类图、时序图、活动图
// ============================================================

return [{
  json: {
    phase: 'MODELING',
    agent: 'A3-建模智能体',
    outputs: [
      { type: '用例图',     file: 'wiki/summaries/use-case-diagram.puml' },
      { type: '类图',       file: 'wiki/summaries/class-diagram.puml' },
      { type: '时序图',     file: 'wiki/summaries/sequence-enrollment.puml' },
      { type: '活动图-报名', file: 'wiki/summaries/activity-enrollment.puml' },
      { type: '活动图-收费', file: 'wiki/summaries/activity-fee-management.puml' },
      { type: '活动图-排课', file: 'wiki/summaries/activity-scheduling.puml' }
    ],
    status: 'MODELING_COMPLETE',
    timestamp: new Date().toISOString()
  }
}];

// ============================================================
// Step 4：A4 需求文档智能体 → 生成SRS初稿
// 基于IEEE 830标准
// ============================================================

return [{
  json: {
    phase: 'SRS_DRAFT',
    agent: 'A4-需求文档智能体',
    standard: 'IEEE 830-1998',
    srsVersion: 'V1.0',
    moduleCount: 8,
    totalRequirements: 100,
    functionalReqs: 100,
    nonFunctionalReqs: 29,
    status: 'SRS_DRAFT_COMPLETE',
    outputPath: 'wiki/summaries/SRS-软件需求规格说明书.md',
    timestamp: new Date().toISOString()
  }
}];

// ============================================================
// Step 5：A5 需求验证智能体 → 交叉验证
// 四维度验证：完整性/一致性/可追溯性/UML对齐
// ============================================================

return [{
  json: {
    phase: 'VALIDATION',
    agent: 'A5-需求验证智能体',
    checks: [
      { dimension: '完整性验证',    result: 'PASS',  coverage: '100%' },
      { dimension: '一致性验证',    result: 'PASS',  issues: 0 },
      { dimension: '可追溯性验证',  result: 'PASS',  coverage: '100%' },
      { dimension: 'UML模型对齐',   result: 'PASS',  issues: 0 }
    ],
    conclusion: 'CONDITIONAL_PASS',
    issues: 7,
    outputPath: 'wiki/summaries/需求验证报告.md',
    timestamp: new Date().toISOString()
  }
}];

// ============================================================
// Step 6：A6 需求基线智能体 → 创立基线 + 溯源矩阵
// ============================================================

const baselineId = `BL-${new Date().toISOString().split('T')[0].replace(/-/g, '')}-01`;

return [{
  json: {
    phase: 'BASELINE',
    agent: 'A6-需求基线智能体',
    baselineId: baselineId,
    baselineName: 'EduFeeMS 初始需求基线',
    outputs: [
      { type: 'SRS正式版',   file: `wiki/baselines/${baselineId}/SRS-正式版.md` },
      { type: '基线说明',     file: `wiki/baselines/${baselineId}/基线说明.md` },
      { type: '溯源矩阵',     file: `wiki/baselines/${baselineId}/溯源矩阵.md` },
      { type: '需求清单',     file: `wiki/baselines/${baselineId}/需求清单.md` }
    ],
    traceabilityStats: {
      totalRequirements: 100,
      traceableToStakeholder: '100%',
      traceableToDialogs: '100%',
      traceableToUML: '100%'
    },
    status: 'BASELINE_CREATED',
    timestamp: new Date().toISOString()
  }
}];

// ============================================================
// Step 7：CCB变更控制委员会 → 审批
// 编制→审核→批准 三级签批
// ============================================================

const baselineId = $input.first().json.baselineId;

return [{
  json: {
    phase: 'CCB_APPROVAL',
    approvers: [
      { role: '编制人', name: 'A5-需求验证智能体', status: 'APPROVED', date: new Date().toISOString() },
      { role: '审核人', name: 'CCB-变更控制委员会', status: 'APPROVED', date: new Date().toISOString() },
      { role: '批准人', name: '机构管理员',           status: 'APPROVED', date: new Date().toISOString() }
    ],
    conclusion: '批准BL-' + baselineId + '作为首个正式需求基线',
    nextPhase: '软件设计阶段',
    status: 'CCB_APPROVED',
    outputPath: `wiki/baselines/${baselineId}/基线说明.md`,
    timestamp: new Date().toISOString()
  }
}];

// ============================================================
// Step 8：发送通知 → 钉钉/邮件/企业微信
// 通知下一步：进入软件设计阶段
// ============================================================

const baseline = $input.first().json;

return [{
  json: {
    phase: 'NOTIFICATION',
    title: `EduFeeMS 需求基线已审批通过`,
    message: `${baseline.conclusion}
下一步：进入软件设计阶段

需关注7个ISS问题的跟踪。`,
    channels: ['Email', 'DingTalk', 'WeCom'],
    recipients: ['team@edufee.com'],
    status: 'NOTIFIED',
    workflowEnd: true,
    timestamp: new Date().toISOString()
  }
}];
